class User_Model_Permission extends User_Model_Base_Permission {

    /**
     * @param string $code
     * @param bool $createIfNotExits Pokud neexistuje, vytvoří
     * @return null|self
     */
    public static function getPermissionByCode(string $code, bool $createIfNotExits = false): ?self {
        $query = Doctrine_Query::create();
        $query->from('User_Model_Permission object');
        $query->where('object.Code = ?', $code);
        $permission = $query->fetchOne();

        if (!$permission && $createIfNotExits) {
            $permission = new self();
            $permission->Code = $code;
            $permission->Name = $code;
            if (!$permission->trySave())
                return null;
        }

        return $permission??null;
    }

    /**
     * @param $userID
     * @return array
     */
    public static function getPermissionsForUser($userID): array {
        $query = Doctrine_Query::create();
        $query->from('User_Model_Permission object');
        $query->select('object.ID, object.Code, IF(COUNT(userHasPermissions.ID),1,0) Access');
        $query->leftJoin('object.userHasPermissions userHasPermissions WITH userHasPermissions.User_ID = ?', $userID);
        $query->groupBy('object.ID');

        $permissions = [];

        try {
            foreach ($query->execute([], Doctrine_Core::HYDRATE_ARRAY) as $perm) {
                $permissions[$perm['Code']] = $perm['Access'] > 0;
            }
        } catch (Doctrine_Query_Exception $ex) { }

        return $permissions;
    }
}